{"id":"c:src/replication.c#replBufWriterAppend@533","source":"static inline void replBufWriterAppend(replBufWriter *wr, const char *buf, size_t len) {
    size_t avail = wr->tail ? wr->tail->size - wr->tail->used : 0;
    if (len > 0 && avail >= len) {
        memcpy(wr->tail->buf + wr->tail->used, buf, len);
        wr->tail->used += len;
        wr->total_len += len;
        return;
    }
    replBufWriterAppendSlow(wr, buf, len);
}"}

